() => {
  const accepted = document.querySelector('.answer.accepted-answer, .answer.js-answer.accepted-answer');
  if (!accepted) return { error: 'Accepted answer not found' };

  const voteEl = accepted.querySelector('.js-vote-count, .vote-count-post');
  const voteText = voteEl ? voteEl.textContent.trim() : null;

  const userLink = accepted.querySelector('.user-details a[href*="/users/"]');
  const author = userLink ? userLink.textContent.trim() : (accepted.querySelector('.user-details')?.textContent.trim() || null);

  const codeBlocks = accepted.querySelectorAll('pre, code').length;

  const h2 = document.querySelector('#answers h2, .answers-subheader h2, h2[data-answercount]');
  let totalAnswers = null;
  if (h2) {
    const txt = h2.textContent || '';
    const m = txt.match(/(\d[\d,]*)\s+Answers?/i);
    if (m) totalAnswers = m[1].replace(/,/g, '');
  }
  if (!totalAnswers) {
    const alt = document.querySelector('[data-answercount]');
    if (alt?.getAttribute('data-answercount')) totalAnswers = alt.getAttribute('data-answercount');
  }

  accepted.scrollIntoView({ behavior: 'instant', block: 'start' });

  return {
    voteText,
    author,
    codeBlocks,
    totalAnswers,
    acceptedId: accepted.id,
    headerText: h2 ? h2.textContent.trim() : null
  };
}

