async (page) => {
  const accepted = page.locator('.answer.accepted-answer').first();
  await accepted.scrollIntoViewIfNeeded();
  await accepted.screenshot({ path: 'eval-so-audit.png', type: 'png' });

  const data = await page.evaluate(() => {
    const acceptedEl = document.querySelector('.answer.accepted-answer');
    if (!acceptedEl) return { error: 'Accepted answer not found' };

    const voteText = acceptedEl.querySelector('.js-vote-count, .vote-count-post')?.textContent?.trim() || '';
    const author = acceptedEl.querySelector('.user-details a[href*="/users/"]')?.textContent?.trim() || '';

    const preCount = acceptedEl.querySelectorAll('pre').length;
    const standaloneCodeCount = [...acceptedEl.querySelectorAll('code')].filter((el) => !el.closest('pre')).length;
    const codeBlockCount = preCount + standaloneCodeCount;

    const answersHeader = document.querySelector('#answers-header h2, #answers h2, .answers-subheader h2');
    const headerText = answersHeader?.textContent || '';
    const m = headerText.match(/(\d[\d,]*)\s+Answers?/i);
    const totalAnswers = m ? m[1].replace(/,/g, '') : '';

    return { voteText, author, codeBlockCount, totalAnswers, preCount, standaloneCodeCount, headerText: headerText.trim() };
  });

  return data;
}

